import React, { useState, useEffect } from 'react';
import { useTable, useGlobalFilter, useSortBy, usePagination } from 'react-table';
import AddMaterial from './AddMaterial';
import EditMaterial from './EditMaterial';
import './MaterialList.css';

const MaterialList = () => {
  const [materials, setMaterials] = useState([]);
  const [vendors, setVendors] = useState([]);
  const [editingMaterial, setEditingMaterial] = useState(null);

  useEffect(() => {
    // Fetch materials from the API
    fetch('http://localhost:8081/MaterialList')
      .then((response) => response.json())
      .then((data) => {
        setMaterials(data);
      })
      .catch((error) => {
        console.log('Error fetching materials:', error);
      });

    // Fetch vendors from the API
    fetch('http://localhost:8081/vendors')
      .then((response) => response.json())
      .then((data) => {
        setVendors(data);
      })
      .catch((error) => {
        console.log('Error fetching vendors:', error);
      });
  }, []);

  const handleAdd = (newMaterial) => {
    // Add the new material to the API
    fetch('http://localhost:8081/MaterialList', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newMaterial),
    })
      .then((response) => response.json())
      .then((data) => {
        setMaterials((prevMaterials) => [...prevMaterials, data]);
      })
      .catch((error) => {
        console.log('Error adding material:', error);
      });
  };

  const handleEdit = (material) => {
    setEditingMaterial(material);
  };

  const handleUpdate = (updatedMaterial) => {
    const previousPrice = editingMaterial.price_per_unit;

    // Update the material in the API
    fetch(`http://localhost:8081/MaterialList/${updatedMaterial.matid}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(updatedMaterial),
    })
      .then((response) => response.json())
      .then((data) => {
        const updatedMaterialList = materials.map((m) =>
          m.matid === updatedMaterial.matid ? updatedMaterial : m
        );
        setMaterials(updatedMaterialList);
        setEditingMaterial(null);

        if (previousPrice !== updatedMaterial.price_per_unit) {
          const materialChange = {
            material_id: updatedMaterial.matid,
            price: updatedMaterial.price_per_unit,
            vendor: updatedMaterial.recent_vendor,
          };

          // Send a POST request to add the material change
          fetch('http://localhost:8081/materialchangesAPI', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
            },
            body: JSON.stringify(materialChange),
          })
            .then((response) => {
              if (!response.ok) {
                throw new Error('Error adding material change');
              }
            })
            .catch((error) => {
              console.log('Error adding material change:', error);
            });
        }
      })
      .catch((error) => {
        console.log('Error updating material:', error);
      });
  };

  const handleDelete = (material) => {
    // Delete the material from the API
    fetch(`http://localhost:8081/MaterialList/${material.matid}`, {
      method: 'DELETE',
    })
      .then((response) => {
        if (response.ok) {
          const updatedMaterialList = materials.filter((m) => m.matid !== material.matid);
          setMaterials(updatedMaterialList);
        } else {
          throw new Error('Error deleting material');
        }
      })
      .catch((error) => {
        console.log('Error deleting material:', error);
      });
  };

  const columns = React.useMemo(
    () => [
      {
        Header: 'Material ID',
        accessor: 'matid',
      },
      {
        Header: 'Name',
        accessor: 'name',
      },
      {
        Header: 'Description',
        accessor: 'description',
      },
      {
        Header: 'Unit of Measure',
        accessor: 'unit_of_measure',
      },
      {
        Header: 'Price per Unit',
        accessor: 'price_per_unit',
      },
      {
        Header: 'Recent Vendor',
        accessor: 'recent_vendor',
        Cell: ({ value }) => {
          const vendor = vendors.find((v) => v.id === value);
          return vendor ? vendor.name : '';
        },
      },
      {
        Header: 'Actions',
        Cell: ({ row }) => (
          <div>
            <button onClick={() => handleEdit(row.original)}>Edit</button>
            <button onClick={() => handleDelete(row.original)}>Delete</button>
          </div>
        ),
      },
    ],
    [vendors, handleEdit, handleDelete]
  );

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state,
    setGlobalFilter,
    canPreviousPage,
    canNextPage,
    pageOptions,
    pageCount,
    gotoPage,
    nextPage,
    previousPage,
    setPageSize,
  } = useTable(
    {
      columns,
      data: materials,
      initialState: { pageIndex: 0, pageSize: 10 },
    },
    useGlobalFilter,
    useSortBy,
    usePagination
  );

  const { globalFilter, pageIndex, pageSize } = state;

  return (
    <div>
      <div>
        <input
          type="search"
          value={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.value)}
          placeholder="Search materials"
        />
      </div>
      <table {...getTableProps()}>
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <React.Fragment key={row.getRowProps().key}>
                <tr {...row.getRowProps()}>
                  {row.cells.map((cell) => (
                    <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                  ))}
                </tr>
                {editingMaterial && editingMaterial.matid === row.original.matid && (
                  <tr>
                    <td colSpan={columns.length}>
                      <EditMaterial material={editingMaterial} handleUpdate={handleUpdate} />
                    </td>
                  </tr>
                )}
              </React.Fragment>
            );
          })}
        </tbody>
      </table>
      <div>
        <button onClick={() => setEditingMaterial({})}>Add Material</button>
      </div>
      {editingMaterial && (
        <EditMaterial material={editingMaterial} handleUpdate={handleUpdate} />
      )}
    </div>
  );
};

export default MaterialList;
